from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from datetime import datetime
from typing import Iterator


@dataclass
class NormalizedDoc:
    doc_id: str
    title: str
    text: str          # markdown; HTML already converted
    url: str
    source: str        # "confluence", "sharepoint", "slack", etc.
    author: str
    updated_at: datetime
    acl_groups: list[str] = field(default_factory=list)
    acl_users: list[str] = field(default_factory=list)
    acl_public: bool = False
    content_hash: str = ""  # sha256 of text; set by connector


class BaseConnector(ABC):
    """Every source connector implements this interface."""

    @abstractmethod
    def list_documents(
        self, since: datetime | None
    ) -> Iterator[dict]:  # yields minimal stubs {doc_id, updated_at}
        ...

    @abstractmethod
    def get_content(self, doc_id: str) -> NormalizedDoc:
        ...

    @abstractmethod
    def get_acl(self, doc_id: str) -> tuple[list[str], list[str], bool]:
        """Returns (acl_groups, acl_users, acl_public)."""
        ...

import time
import httpx


class OAuth2TokenManager:
    def __init__(self, token_url: str, client_id: str, client_secret: str,
                 refresh_token: str):
        self._token_url = token_url
        self._client_id = client_id
        self._client_secret = client_secret
        self._refresh_token = refresh_token
        self._access_token: str | None = None
        self._expires_at: float = 0.0

    def get_token(self) -> str:
        # Refresh 60s before expiry to avoid clock skew races
        if time.time() < self._expires_at - 60 and self._access_token:
            return self._access_token
        return self._refresh()

    def _refresh(self) -> str:
        resp = httpx.post(
            self._token_url,
            data={
                "grant_type": "refresh_token",
                "refresh_token": self._refresh_token,
                "client_id": self._client_id,
                "client_secret": self._client_secret,
            },
        )
        resp.raise_for_status()
        data = resp.json()
        self._access_token = data["access_token"]
        self._expires_at = time.time() + data.get("expires_in", 3600)
        # If the provider rotated the refresh token, persist the new one
        if "refresh_token" in data:
            self._refresh_token = data["refresh_token"]
        return self._access_token

    def auth_headers(self) -> dict:
        return {"Authorization": f"Bearer {self.get_token()}"}

import hashlib
import time
from datetime import datetime, timezone

import httpx


class ConfluenceConnector(BaseConnector):
    BASE = "https://your-org.atlassian.net/wiki/rest/api"

    def __init__(self, token_manager: OAuth2TokenManager):
        self._tokens = token_manager

    def _get(self, path: str, params: dict | None = None,
             max_retries: int = 5) -> dict:
        delay = 1.0
        for attempt in range(max_retries):
            resp = httpx.get(
                f"{self.BASE}{path}",
                headers=self._tokens.auth_headers(),
                params=params or {},
            )
            if resp.status_code == 429:
                retry_after = float(resp.headers.get("Retry-After", delay))
                time.sleep(retry_after)
                delay = min(delay * 2, 60)
                continue
            resp.raise_for_status()
            return resp.json()
        raise RuntimeError(f"Rate limited after {max_retries} retries on {path}")

    def list_documents(
        self, since: datetime | None
    ) -> Iterator[dict]:
        start = 0
        limit = 50
        while True:
            params = {"start": start, "limit": limit, "expand": "version"}
            if since:
                # Confluence CQL: modified_after is inclusive
                params["cql"] = (
                    f'lastModified >= "{since.strftime("%Y-%m-%d %H:%M")}"'
                )
            data = self._get("/content/search", params)
            for result in data["results"]:
                yield {"doc_id": result["id"], "updated_at": result["version"]["when"]}
            if "next" not in data.get("_links", {}):
                break
            start += limit

    def get_content(self, doc_id: str) -> NormalizedDoc:
        page = self._get(f"/content/{doc_id}",
                         {"expand": "body.storage,metadata.labels,space"})
        html_body = page["body"]["storage"]["value"]
        text = _html_to_markdown(html_body)
        acl_groups, acl_users, acl_public = self.get_acl(doc_id)
        updated_at = datetime.fromisoformat(
            page["version"]["when"].replace("Z", "+00:00")
        )
        return NormalizedDoc(
            doc_id=doc_id,
            title=page["title"],
            text=text,
            url=f"https://your-org.atlassian.net/wiki{page['_links']['webui']}",
            source="confluence",
            author=page["version"]["by"].get("displayName", ""),
            updated_at=updated_at,
            acl_groups=acl_groups,
            acl_users=acl_users,
            acl_public=acl_public,
            content_hash=hashlib.sha256(text.encode()).hexdigest(),
        )

    def get_acl(self, doc_id: str) -> tuple[list[str], list[str], bool]:
        # Confluence REST: GET /content/{id}/restriction/byOperation/read
        restrictions = self._get(
            f"/content/{doc_id}/restriction/byOperation/read"
        )
        groups, users = [], []
        for group in restrictions.get("group", {}).get("results", []):
            groups.append(group["name"])
        for user in restrictions.get("user", {}).get("results", []):
            users.append(user.get("email", user["accountId"]))
        # Empty restrictions on Confluence = open to all space members
        is_public = len(groups) == 0 and len(users) == 0
        return groups, users, is_public

import asyncio
import logging
from datetime import datetime, timezone

logger = logging.getLogger(__name__)


class ConnectorRegistry:
    def __init__(self, ingestion_pipeline, cursor_store):
        self._connectors: dict[str, BaseConnector] = {}
        self._pipeline = ingestion_pipeline
        self._cursors = cursor_store  # dict-like: {connector_id: datetime}

    def register(self, connector_id: str, connector: BaseConnector) -> None:
        self._connectors[connector_id] = connector

    async def run_all(self) -> dict[str, int]:
        """Run all connectors; return {connector_id: docs_processed}."""
        results = await asyncio.gather(
            *[self._run_one(cid, c) for cid, c in self._connectors.items()],
            return_exceptions=True,
        )
        return {
            cid: r if isinstance(r, int) else 0
            for cid, r in zip(self._connectors, results)
        }

    async def _run_one(self, connector_id: str, connector: BaseConnector) -> int:
        since = self._cursors.get(connector_id)  # None on first run = full sync
        started_at = datetime.now(tz=timezone.utc)
        processed = 0
        try:
            for stub in connector.list_documents(since):
                try:
                    doc = connector.get_content(stub["doc_id"])
                    await self._pipeline.upsert(doc)
                    processed += 1
                except Exception:
                    logger.exception("Failed to sync doc %s", stub["doc_id"])
            # Only advance cursor after a clean run
            self._cursors[connector_id] = started_at
            return processed
        except Exception:
            logger.exception("Connector %s failed; cursor not advanced", connector_id)
            raise
